parameters.jsCode:
// Docuseal envoie l'evenement form.completed apres signature.
// Les metadonnees du rendez-vous sont dans data.metadata.
const body = $json.body || $json;
const data = body.data || {};
const meta = data.metadata || {};

if (!meta.date || !meta.heure) {
  return [];
}

const start = DateTime.fromISO(`${meta.date}T${meta.heure}`, { zone: 'Europe/Paris' });
const end = start.plus({ hours: 1 });
const zohoFmt = "yyyyLLdd'T'HHmmssZZZ";

const eventdata = JSON.stringify({
  dateandtime: {
    timezone: 'Europe/Paris',
    start: start.toFormat(zohoFmt),
    end: end.toFormat(zohoFmt),
  },
  title: `Devis - ${meta.devis_numero || ''} - ${meta.prenom || ''} ${meta.nom || ''}`.trim(),
  location: meta.adresse || '',
  description: `Client: ${meta.prenom || ''} ${meta.nom || ''}\nTel: ${meta.telephone || ''}\nEmail: ${meta.email || ''}\nSurface: ${meta.surface_m2 || ''} m2\nType: ${meta.type_toiture || ''}\nDevis: ${meta.devis_total_ttc || ''} EUR`,
  isallday: false,
});

// Rappel 45 min apres le debut = 15 min avant la fin du RDV d'1h
const reminderTime = start.plus({ minutes: 45 }).toISO();

return [{ json: {
  eventdata,
  reminderTime,
  prenom: meta.prenom || '',
  nom: meta.nom || '',
  adresse: meta.adresse || '',
  telephone: meta.telephone || '',
  devis_numero: meta.devis_numero || '',
  heure: meta.heure || '',
  date: meta.date || '',
}}];

// Attend que reminderTime soit atteint (45 min apres debut = 15 min avant fin)
const { reminderTime, prenom, nom, adresse, telephone, devis_numero, heure, date } = $json;
if (!reminderTime) return [];
return [{ json: { reminderTime, prenom, nom, adresse, telephone, devis_numero, heure, date } }];

